mapper.select:
select
from appointment a left join customer c on a.customer_id = c.id left join employee e on a.employee_id = e.id left join service_item si on a.service_item_id = si.id
and c.name like concat('%', #{customerName}, '%')
and e.name like concat('%', #{employeeName}, '%')
and a.status = #{status}
and a.appointment_time >= #{beginTime}
and a.appointment_time <= #{endTime}
order by a.create_time desc
